+fn parse_waitaof_deadline_argv(argv: &[Vec<u8>], now_ms: u64) -> Option<u64> {
+    if argv.len() != 4 {
+        return None;
+    }
+    let timeout_ms: i64 = std::str::from_utf8(&argv[3]).ok()?.parse().ok()?;
+    if timeout_ms < 0 {
+        return None;
+    }
+    if timeout_ms == 0 {
+        return Some(u64::MAX);
+    }
+    now_ms.checked_add(timeout_ms as u64)
+}
